import sys

class Solution:

def __init__(self):
	pass



def validate_stack(self, s: str) -> bool: 
	count = 0; 
	for c in s: 
		if c in ['(', '{', '[']: 
			count += 1 
		else: 
			count -= 1 
		if count < 0: 
			return False 
	return True

def read_input(): 
	input_str = sys.stdin.readline().strip() 
	return input_str.strip()

solution = Solution()

input_str = read_input() 
	result = solution.validate_stack(input_str) 
	print(result)

